"use client";
import React, { Suspense } from "react";
import { Canvas } from "@react-three/fiber";
import { Preload } from "@react-three/drei";
import StarsContainer from "../models/Stars";
import CloudContainer from "../models/Cloud";

const PassiveBackgroundContent = () => {
  return (
    <>
      <ambientLight intensity={0.4} />
      {/* 3D Stars background (particles system) */}
      <StarsContainer />
      {/* Subtle cloud particles floating passively */}
      <CloudContainer />
    </>
  );
};

const ThreeBackground = React.memo(() => {
  return (
    <div id="canvas-container" style={{ pointerEvents: "none", zIndex: 0 }}>
      <Canvas
        camera={{ position: [0, 0, 5], fov: 75 }}
        gl={{ antialias: true, alpha: true }}
        dpr={[1, 1.5]}
      >
        <Suspense fallback={null}>
          <PassiveBackgroundContent />
          <Preload all />
        </Suspense>
      </Canvas>
    </div>
  );
});

ThreeBackground.displayName = "ThreeBackground";
export default ThreeBackground;
